from collections import OrderedDict

class IndexCache:
    def __init__(self):
        self.caches = {}

    def get_cache(self, index_file):
        if index_file not in self.caches:
            self.caches[index_file] = OrderedDict()
        return self.caches[index_file]

    def add_to_cache(self, index_file, key, value):
        cache = self.get_cache(index_file)
        cache[key] = value

    def get_from_cache(self, index_file, key):
        cache = self.get_cache(index_file)
        return cache.get(key)

    def remove_from_cache(self, index_file, key):
        cache = self.get_cache(index_file)
        cache.pop(key, None)
